const t=!0,richTypes={Date:t,RegExp:t,String:t,Number:t};export default function diff(t,e){let p=[];for(const o in t)if(o in e)if(t[o]&&e[o]&&"object"==typeof t[o]&&"object"==typeof e[o]&&!richTypes[Object.getPrototypeOf(t[o]).constructor.name]){const f=diff(t[o],e[o]);p.push(...f.map(t=>(t.path.unshift(o),t)))}else t[o]===e[o]||"object"==typeof t[o]&&"object"==typeof e[o]&&(isNaN(t[o])?t[o]+""==e[o]+"":+t[o]==+e[o])||p.push({path:[o],type:"CHANGE",value:e[o]});else p.push({type:"REMOVE",path:[o]});for(const n in e)n in t||p.push({type:"CREATE",path:[n],value:e[n]});return p}